/**
 * `<tot-dropdown>` - a positioned `<tot-menu>` opened by a `<tot-button>`.
 * The built-in trigger and generated panel delegate their rendering and state to
 * those components rather than duplicating button or menu implementations.
 */
export type TotDropdown = {
  props: {
    /** Fallback trigger-button label. Ignored when the `trigger` slot is used. @default 'Dropdown' */
    label: string

    /**
     * Proxied to the generated `<tot-menu>` using the same canonical menu-data
     * format. A slotted menu takes visual precedence. @default []
     */
    items: TotDropdownMenuConfig[]

    /** Whether the panel is visible. @default false */
    open: boolean

    /**
     * Uses viewport-fixed positioning with automatic flipping to avoid clipping.
     * Without it, the panel is positioned below the trigger in local layout.
     * @default false
     */
    hoist: boolean

    /** Keeps the panel open after a leaf menu item is selected. @default false */
    stayOpenOnSelect: boolean
  }

  methods: {
    show(): void
    hide(): void
    toggle(): void
    focus(options?: FocusOptions): void
    getTrigger(): HTMLElement | null
    /** Returns the slotted menu when present, otherwise the generated menu. */
    getMenu(): HTMLElement | null
  }

  /** The active menu selection re-emitted without exposing the menu-item element. */
  events: {
    select: CustomEvent<{
      value: string
      label: string
    }>
  }

  slots: {
    /** A `<tot-menu>` that replaces the generated menu. Other elements are ignored. */
    default: undefined
    /** A custom trigger that replaces the generated `<tot-button>`. */
    trigger: undefined
  }

  /**
   * ```text
   * base — positioned dropdown wrapper
   * ├─ trigger
   * │  └─ button — generated `<tot-button>` when the trigger slot is empty
   * └─ panel
   *    └─ menu — generated `<tot-menu>` when the default slot has no menu
   * ```
   */
  parts: 'base' | 'trigger' | 'button' | 'panel' | 'menu'
}

/**
 * `<tot-dialog>` - a compact confirm/cancel dialog built on the same overlay
 * and stacking behavior as `<tot-modal>`. It keeps a bounded layout on narrow
 * screens and supplies default footer actions when the `footer` slot is empty.
 */
export type TotDialog = {
  props: {
    /** Fallback used when the `header` slot is empty. @default '' */
    header: string

    /**
     * Final body fallback, used only when both the named `body` slot and default
     * slot are empty. @default ''
     */
    content: string

    /** Whether the dialog is visible. @default false */
    open: boolean

    /** Label of the built-in confirm button. @default 'Confirm' */
    confirmLabel: string

    /** Label of the built-in cancel button. @default 'Cancel' */
    cancelLabel: string

    /** Variant of the built-in confirm button. @default 'primary' */
    confirmVariant: 'default' | 'primary' | 'danger' | 'create'

    /** Hides the built-in cancel button. @default false */
    hideCancel: boolean

    /** Hides the built-in confirm button. @default false */
    hideConfirm: boolean

    /** Hides the complete footer, including slotted footer content. @default false */
    hideFooter: boolean

    /** Hides only the header close button. Escape, Back, and overlay closing remain available. @default false */
    noClose: boolean

    /**
     * Allows a pointer press and release directly on the topmost overlay to
     * close the dialog with reason `overlay`. @default true
     */
    closeOnOverlay: boolean
  }

  methods: {
    show(): void
    /** Hides with reason `programmatic`. */
    hide(): void
    /** Hides with reason `confirm`. */
    confirm(): void
    /** Hides with the supplied reason, or `cancel` by default. */
    cancel(reason?: string): void
    getOverlay(): HTMLElement | null
    getBase(): HTMLElement | null
    getHeader(): HTMLElement | null
    getTitle(): HTMLElement | null
    getBody(): HTMLElement | null
    getFooter(): HTMLElement | null
    getCloseButton(): HTMLButtonElement | null
    getCancelButton(): HTMLElement | null
    getConfirmButton(): HTMLElement | null
  }

  /**
   * Both events bubble and are composed. `show` carries no detail. `hide`
   * carries only the close reason, such as `confirm`, `cancel`, `close`,
   * `overlay`, `escape`, `back`, `programmatic`, or a custom value supplied to
   * `cancel(reason)`.
   */
  events: {
    show: Event
    hide: CustomEvent<{ reason: string }>
  }

  /** Slotted nodes receive no added attributes or slot props. */
  slots: {
    /** Header content. Takes precedence over `header`. */
    header: undefined
    /** Body content, used when the named `body` slot is empty. */
    default: undefined
    /** Named body content. Takes precedence over the default slot and `content`. */
    body: undefined
    /** Replaces the built-in confirm/cancel actions. */
    footer: undefined
  }

  /**
   * ```text
   * overlay — fixed viewport layer; participates in the shared modal backdrop
   * └─ base — compact dialog surface
   *    ├─ header
   *    │  ├─ title
   *    │  └─ close-button — native button
   *    ├─ body
   *    └─ footer
   *       └─ actions — fallback action row when the footer slot is empty
   *          ├─ cancel-button — generated `<tot-button>`
   *          └─ confirm-button — generated `<tot-button>`
   * ```
   */
  parts:
    | 'overlay'
    | 'base'
    | 'header'
    | 'title'
    | 'close-button'
    | 'body'
    | 'footer'
    | 'actions'
    | 'cancel-button'
    | 'confirm-button'
}

/**
 * `<tot-drawer>` - a viewport or container edge panel with optional resizing.
 */
export type TotDrawer = {
  props: {
    /** Fallback used when the `label` slot is empty. @default '' */
    label: string

    /** Whether the drawer is visible. @default false */
    open: boolean

    /** Edge from which the drawer opens. @default 'end' */
    placement: 'top' | 'end' | 'bottom' | 'start'

    /**
     * Positions the drawer inside its containing block, removes the overlay,
     * and disables Escape/Back dismissal. The parent must establish a
     * positioned containing block. @default false
     */
    contained: boolean

    /** Hides the complete header. @default false */
    noHeader: boolean

    /** Enables pointer and keyboard resizing from the panel edge. @default false */
    resizable: boolean

    /** Minimum resize extent as a CSS length. @default '12rem' */
    minSize: string

    /** Maximum resize extent as a CSS length. @default '100%' */
    maxSize: string
  }

  methods: {
    show(): void
    hide(): void
    focus(options?: FocusOptions): void
    getBase(): HTMLElement | null
    getPanel(): HTMLElement | null
    getHeader(): HTMLElement | null
    getBody(): HTMLElement | null
    getFooter(): HTMLElement | null
    getCloseButton(): HTMLButtonElement | null
    getResizeHandle(): HTMLButtonElement | null
  }

  /**
   * `show` and `hide` are detail-free lifecycle events. `request-close` is
   * emitted only for user dismissal attempts and can be canceled to keep the
   * drawer open.
   */
  events: {
    show: Event
    hide: Event
    'request-close': CustomEvent<{
      reason: 'overlay' | 'close' | 'escape' | 'back'
    }>
  }

  /** Slotted nodes receive no added attributes or slot props. */
  slots: {
    /** Main scrolling drawer content. */
    default: undefined
    /** Header title; takes precedence over `label`. */
    label: undefined
    /** Content before the built-in close button. */
    'header-actions': undefined
    /** Footer content; the footer is hidden while empty. */
    footer: undefined
  }

  /**
   * ```text
   * base — complete fixed or contained drawer layer
   * ├─ overlay — omitted visually in contained mode
   * └─ panel — dialog surface
   *    ├─ header
   *    │  ├─ title
   *    │  └─ header-actions
   *    │     └─ close-button — native button
   *    ├─ body
   *    ├─ footer — hidden while its slot is empty
   *    └─ resize-handle — native button, visible when resizable
   * ```
   */
  parts:
    | 'base'
    | 'overlay'
    | 'panel'
    | 'header'
    | 'title'
    | 'header-actions'
    | 'close-button'
    | 'body'
    | 'footer'
    | 'resize-handle'
}

